**Location:** Text handling in `TextGenerationPipeline` (lines 984-1080)

**Chat Template Implementation:**
```javascript
// Helper function to detect chat format
function isChat(x) {
    return Array.isArray(x) && x.every(x => 'role' in x && 'content' in x);
}

// In TextGenerationPipeline._call():
async _call(texts, generate_kwargs = {}) {
    let isBatched = false;
    let isChatInput = false;

    // Handle both string and chat inputs
    let inputs;
    if (typeof texts === 'string') {
        inputs = texts = [texts];
    } else if (Array.isArray(texts) && texts.every(x => typeof x === 'string')) {
        isBatched = true;
        inputs = texts;
    } else {
        if (isChat(texts)) {
            texts = [texts];
        } else if (Array.isArray(texts) && texts.every(isChat)) {
            isBatched = true;
        } else {
            throw new Error('Input must be a string, an array of strings, a Chat, or an array of Chats');
        }
        isChatInput = true;

        // Apply chat template via tokenizer
        inputs = texts.map(
            x => this.tokenizer.apply_chat_template(x, {
                tokenize: false,
                add_generation_prompt: true,
            })
        );
        add_special_tokens = false; // Chat template handles this already
    }

    // Generate using the model
    const outputTokenIds = await this.model.generate({
        ...text_inputs,
        ...generate_kwargs
    });

    // Return formatted output
    const decoded = this.tokenizer.batch_decode(outputTokenIds, {
        skip_special_tokens: true,
    });

    // Format back to chat format if input was chat
    if (isChatInput) {
        generated_text: [
            ...((texts[textIndex])),
            { role: 'assistant', content: decoded[i] },
        ]
    }
}
