/**
 * Image-text-to-text pipeline using `AutoModelForImageTextToText`. This pipeline accepts
 * a conversation containing image and text inputs and returns generated text.
 *
 * **Example:** Generate a response for an image and text prompt w/ `onnx-community/SmolVLM-500M-Instruct`.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'onnx-community/SmolVLM-500M-Instruct');
 * const url = 'https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/bee.jpg';
 * const messages = [
 *   {
 *     role: 'user',
 *     content: [
 *       { type: 'image', image: url },
 *       { type: 'text', text: 'Describe the image in detail.' },
 *     ],
 *   },
 * ];
 * const output = await pipe(messages);
 * // [{ generated_text: [{ role: 'user', content: [...] }, { role: 'assistant', content: 'The image shows a bee...' }] }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(inputs, generate_kwargs = {}) {
        let isBatched = false;
        /** @type {import('./tokenizers.js').Message[][]} */
        let chats;

        if (isChat(inputs)) {
            chats = [/** @type {import('./tokenizers.js').Message[]} */(inputs)];
        } else if (Array.isArray(inputs) && inputs.every(isChat)) {
            isBatched = true;
            chats = /** @type {import('./tokenizers.js').Message[][]} */(inputs);
        } else {
            throw new Error('The pipeline input must be a Chat or an array of Chats. ' +
                'A Chat is an array of objects with "role" and "content" properties.');
        }

        /** @type {ImageTextToTextOutput[]} */
        const toReturn = [];
        for (const chat of chats) {

            // Extract all images referenced in the chat content
            const imageInputs = [];
            for (const message of chat) {
                if (Array.isArray(message.content)) {
                    for (const item of message.content) {
                        if (item.type === 'image') {
                            imageInputs.push(item.image);
                        }
                    }
                }
            }

            // Apply chat template to produce text with model-specific image tokens
            const formattedText = this.processor.apply_chat_template(chat, {
                tokenize: false,
                add_generation_prompt: true,
            });

            // Prepare raw images and call the processor for combined model inputs
            const preparedImages = imageInputs.length > 0
                ? await prepareImages(imageInputs)
                : null;
            const model_inputs = await this.processor(formattedText, preparedImages);

            // Generate output token ids
            const outputTokenIds = /** @type {Tensor} */(await this.model.generate({
                ...model_inputs,
                ...generate_kwargs,
            }));

            // Decode the prompt to measure its character length for trimming
            const promptText = this.tokenizer.batch_decode(model_inputs.input_ids, {
                skip_special_tokens: true,
            })[0];

            // Decode the full output (prompt + generated), then strip the prompt prefix
            const decoded = this.tokenizer.batch_decode(outputTokenIds, {
                skip_special_tokens: true,
            });

            const results = decoded.map(text => ({
                generated_text: [
                    ...chat,
                    { role: 'assistant', content: text.slice(promptText.length) },
                ],
            }));

            toReturn.push(results);
        }

        return isBatched ? toReturn : toReturn[0];
    }
}

