import { pipeline, ImageTextToTextPipeline } from "../../src/transformers.js";

import { MAX_MODEL_LOAD_TIME, MAX_TEST_EXECUTION_TIME, MAX_MODEL_DISPOSE_TIME, DEFAULT_MODEL_OPTIONS } from "../init.js";
import { load_cached_image } from "../asset_cache.js";

const PIPELINE_ID = "image-text-to-text";

export default () => {
  describe("Image Text To Text", () => {
    const model_id = "hf-internal-testing/tiny-random-LlavaForConditionalGeneration";
    /** @type {ImageTextToTextPipeline} */
    let pipe;
    let images;
    beforeAll(async () => {
      pipe = await pipeline(PIPELINE_ID, model_id, DEFAULT_MODEL_OPTIONS);
      images = await Promise.all([load_cached_image("white_image"), load_cached_image("blue_image")]);
    }, MAX_MODEL_LOAD_TIME);

    it("should be an instance of ImageTextToTextPipeline", () => {
      expect(pipe).toBeInstanceOf(ImageTextToTextPipeline);
    });

    describe("batch_size=1", () => {
      it(
        "default",
        async () => {
          const messages = [
            {
              role: "user",
              content: [
                { type: "image", image: images[0] },
                { type: "text", text: "Describe the image." },
              ],
            },
          ];
          const output = await pipe(messages);
          expect(Array.isArray(output)).toBe(true);
          expect(output.length).toBeGreaterThan(0);
          const item = output[0];
          expect(item).toHaveProperty("generated_text");
          expect(Array.isArray(item.generated_text)).toBe(true);
          const lastMessage = item.generated_text.at(-1);
          expect(lastMessage).toHaveProperty("role", "assistant");
          expect(typeof lastMessage.content).toBe("string");
        },
        MAX_TEST_EXECUTION_TIME,
      );
    });

    describe("batch_size>1", () => {
      it(
        "default",
        async () => {
          const batch = [
            [
              {
                role: "user",
                content: [
                  { type: "image", image: images[0] },
                  { type: "text", text: "Describe this image." },
                ],
              },
            ],
            [
              {
                role: "user",
                content: [
                  { type: "image", image: images[1] },
                  { type: "text", text: "What color is this?" },
                ],
              },
            ],
          ];
          const output = await pipe(batch);
          expect(Array.isArray(output)).toBe(true);
          expect(output).toHaveLength(2);
          for (const result of output) {
            expect(Array.isArray(result)).toBe(true);
            expect(result.length).toBeGreaterThan(0);
            const lastMessage = result[0].generated_text.at(-1);
            expect(lastMessage).toHaveProperty("role", "assistant");
          }
        },
        MAX_TEST_EXECUTION_TIME,
      );
    });

    afterAll(async () => {
      await pipe.dispose();
    }, MAX_MODEL_DISPOSE_TIME);
  });
};

