2053	    async _call(inputs, generate_kwargs = {}) {
2054	        let isBatched = false;
2055	        /** @type {import('./tokenizers.js').Message[][]} */
2056	        let chats;
2057	
2058	        if (isChat(inputs)) {
2059	            chats = [/** @type {import('./tokenizers.js').Message[]} */(inputs)];
2060	        } else if (Array.isArray(inputs) && inputs.every(isChat)) {
2061	            isBatched = true;
