2067	
2068	        /** @type {ImageTextToTextOutput[]} */
2069	        const toReturn = [];
2070	        for (const chat of chats) {
2071	
2072	            // Extract all images referenced in the chat content
2073	            const imageInputs = [];
2074	            for (const message of chat) {
2075	                if (Array.isArray(message.content)) {
2076	                    for (const item of message.content) {
2077	                        if (item.type === 'image') {
2078	                            imageInputs.push(item.image);
