2092	                ? await prepareImages(imageInputs)
2093	                : null;
2094	            const model_inputs = await this.processor(formattedText, preparedImages);
2095	
2096	            // Generate output token ids
2097	            const outputTokenIds = /** @type {Tensor} */(await this.model.generate({
2098	                ...model_inputs,
2099	                ...generate_kwargs,
2100	            }));
2101	
2102	            // Decode the prompt to measure its character length for trimming
2103	            const promptText = this.tokenizer.batch_decode(model_inputs.input_ids, {
2104	                skip_special_tokens: true,
2105	            })[0];
2106	
